const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

const PORT = process.env.PORT || 3000;
const SESSION_TTL_MS = 1000 * 60 * 60 * 24;
const MAX_USERNAME_LENGTH = 32;
const MAX_MOVE_LENGTH = 128;

const sessions = new Map();
const players = new Map();
const leaderboard = new Map();

function now() {
  return Date.now();
}

function generateId(bytes = 24) {
  return crypto.randomBytes(bytes).toString('hex');
}

function sanitizeUsername(username) {
  if (typeof username !== 'string') return null;
  const trimmed = username.trim();
  if (!trimmed || trimmed.length > MAX_USERNAME_LENGTH) return null;
  if (!/^[a-zA-Z0-9_\- ]+$/.test(trimmed)) return null;
  return trimmed;
}

function sanitizeScore(score) {
  const n = Number(score);
  if (!Number.isFinite(n) || n < 0) return null;
  return Math.floor(n);
}

function sanitizeMove(move) {
  if (typeof move !== 'string') return null;
  const trimmed = move.trim();
  if (!trimmed || trimmed.length > MAX_MOVE_LENGTH) return null;
  return trimmed;
}

function createSession(username) {
  const sessionId = generateId();
  const playerId = generateId(12);
  const session = {
    sessionId,
    playerId,
    username,
    createdAt: now(),
    expiresAt: now() + SESSION_TTL_MS
  };
  sessions.set(sessionId, session);
  return session;
}

function getSession(sessionId) {
  const session = sessions.get(sessionId);
  if (!session) return null;
  if (session.expiresAt < now()) {
    sessions.delete(sessionId);
    return null;
  }
  return session;
}

function touchSession(sessionId) {
  const session = sessions.get(sessionId);
  if (!session) return null;
  session.expiresAt = now() + SESSION_TTL_MS;
  return session;
}

function updateLeaderboard(playerId, username, score) {
  const current = leaderboard.get(playerId);
  if (!current || score > current.score) {
    leaderboard.set(playerId, { playerId, username, score, updatedAt: now() });
  }
}

function getLeaderboard(limit = 10) {
  return [...leaderboard.values()]
    .sort((a, b) => b.score - a.score || a.updatedAt - b.updatedAt)
    .slice(0, limit);
}

app.post('/auth/login', (req, res) => {
  const username = sanitizeUsername(req.body?.username);
  if (!username) {
    return res.status(400).json({ error: 'Invalid username' });
  }

  const session = createSession(username);
  return res.json({
    sessionId: session.sessionId,
    playerId: session.playerId,
    username: session.username,
    expiresAt: session.expiresAt
  });
});

app.post('/auth/restore', (req, res) => {
  const sessionId = typeof req.body?.sessionId === 'string' ? req.body.sessionId : null;
  const session = sessionId ? getSession(sessionId) : null;

  if (!session) {
    return res.status(401).json({ error: 'Invalid or expired session' });
  }

  touchSession(session.sessionId);
  return res.json({
    sessionId: session.sessionId,
    playerId: session.playerId,
    username: session.username,
    expiresAt: session.expiresAt
  });
});

app.post('/auth/logout', (req, res) => {
  const sessionId = typeof req.body?.sessionId === 'string' ? req.body.sessionId : null;
  if (sessionId) {
    sessions.delete(sessionId);
  }
  return res.json({ ok: true });
});

app.get('/leaderboard', (req, res) => {
  const limit = Math.min(Math.max(Number(req.query.limit) || 10, 1), 100);
  res.json({ leaderboard: getLeaderboard(limit) });
});

io.use((socket, next) => {
  const auth = socket.handshake.auth || {};
  const sessionId = typeof auth.sessionId === 'string' ? auth.sessionId : null;
  const session = sessionId ? getSession(sessionId) : null;

  if (!session) {
    return next(new Error('Unauthorized'));
  }

  touchSession(sessionId);
  socket.data.session = session;
  next();
});

io.on('connection', (socket) => {
  const session = socket.data.session;
  const player = {
    socketId: socket.id,
    playerId: session.playerId,
    username: session.username,
    connectedAt: now(),
    lastSeenAt: now(),
    score: leaderboard.get(session.playerId)?.score || 0
  };

  players.set(socket.id, player);
  socket.join('global');

  socket.emit('session', {
    playerId: player.playerId,
    username: player.username,
    expiresAt: session.expiresAt
  });

  socket.emit('leaderboard:update', getLeaderboard(10));

  socket.broadcast.emit('player:joined', {
    playerId: player.playerId,
    username: player.username
  });

  socket.on('player:move', (payload = {}) => {
    const move = sanitizeMove(payload.move);
    if (!move) {
      socket.emit('error:message', { error: 'Invalid move' });
      return;
    }

    player.lastSeenAt = now();

    io.to('global').emit('player:moved', {
      playerId: player.playerId,
      username: player.username,
      move,
      at: now()
    });
  });

  socket.on('player:score', (payload = {}) => {
    const score = sanitizeScore(payload.score);
    if (score === null) {
      socket.emit('error:message', { error: 'Invalid score' });
      return;
    }

    player.lastSeenAt = now();
    player.score = score;
    updateLeaderboard(player.playerId, player.username, score);

    io.to('global').emit('leaderboard:update', getLeaderboard(10));
  });

  socket.on('session:refresh', () => {
    const refreshed = touchSession(session.sessionId);
    if (!refreshed) {
      socket.emit('error:message', { error: 'Session expired' });
      socket.disconnect(true);
      return;
    }

    socket.emit('session', {
      playerId: refreshed.playerId,
      username: refreshed.username,
      expiresAt: refreshed.expiresAt
    });
  });

  socket.on('disconnect', () => {
    players.delete(socket.id);
    socket.broadcast.emit('player:left', {
      playerId: player.playerId,
      username: player.username
    });
  });
});

setInterval(() => {
  const current = now();
  for (const [sessionId, session] of sessions.entries()) {
    if (session.expiresAt < current) {
      sessions.delete(sessionId);
    }
  }
}, 60 * 1000);

server.listen(PORT, () => {
  console.log(`Game server listening on port ${PORT}`);
});